import{_ as a,o as l,c as e,a2 as i}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"苹果公司","description":"","frontmatter":{"title":"苹果公司"},"headers":[],"relativePath":"03_companies/苹果公司.md","filePath":"03_companies/苹果公司.md"}'),r={name:"03_companies/苹果公司.md"};function o(h,t,n,s,d,_){return l(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="苹果公司" tabindex="-1">苹果公司 <a class="header-anchor" href="#苹果公司" aria-label="Permalink to &quot;苹果公司&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><ul><li><strong>首次提及</strong>: 2016年</li><li><strong>持股情况</strong>: <ul><li>2016年末：开始购买</li><li>2018年7月：持有略多于10亿股</li><li>2020年：持有5.4%股权</li><li>2021年：持有5.55%股权</li></ul></li><li><strong>行业</strong>: 科技消费电子</li><li><strong>英文名</strong>: Apple Inc.</li><li><strong>CEO</strong>: 蒂姆·库克</li></ul><h2 id="巴菲特论述" tabindex="-1">巴菲特论述 <a class="header-anchor" href="#巴菲特论述" aria-label="Permalink to &quot;巴菲特论述&quot;">​</a></h2><p>苹果是伯克希尔的&quot;四大珍宝&quot;之一，也是巴菲特近年来最成功的投资之一。</p><p>2016年末开始购买，到2018年7月初持有略多于10亿股。通过苹果的股票回购，伯克希尔的持股比例自动增加，无需任何成本——这正是巴菲特欣赏苹果资本配置能力的体现。</p><p>持股成本约360亿美元（账面成本310.89亿美元），2020年市值达1204.24亿美元，2021年进一步增长至1611.55亿美元。苹果2021年收益中伯克希尔的份额达56亿美元，获得股息7.85亿美元。</p><h2 id="投资逻辑" tabindex="-1">投资逻辑 <a class="header-anchor" href="#投资逻辑" aria-label="Permalink to &quot;投资逻辑&quot;">​</a></h2><p>巴菲特将苹果视为&quot;消费品牌&quot;而非科技公司：</p><ul><li>强大的品牌忠诚度和生态系统</li><li>用户更换成本高，形成护城河</li><li>优秀的资本配置（大规模股票回购）</li><li>持续增长的股息</li><li>蒂姆·库克出色的管理能力</li></ul><h2 id="市值变化" tabindex="-1">市值变化 <a class="header-anchor" href="#市值变化" aria-label="Permalink to &quot;市值变化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>市值</th></tr></thead><tbody><tr><td>2020年</td><td>1204.24亿美元</td></tr><tr><td>2021年</td><td>1611.55亿美元</td></tr></tbody></table><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2016, 2018, 2020, 2021, 2022, 2023, 2024</p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/2016年/翻译.html">2016年</a></li><li><a href="./../01_letters/2017年/翻译.html">2017年</a></li><li><a href="./../01_letters/2018年/翻译.html">2018年</a></li><li><a href="./../01_letters/2019年/翻译.html">2019年</a></li><li><a href="./../01_letters/2020年/翻译.html">2020年</a></li><li><a href="./../01_letters/2021年/翻译.html">2021年</a></li></ul>',16)])])}const p=a(r,[["render",o]]);export{u as __pageData,p as default};
